            if r == 3 or r == 7 or c == 3 or c == 7:
                out[r][c] = 5
    # Find block with value 4
    for bi in range(3):
        for bj in range(3):
            r0, c0 = bi*4, bj*4
            for r in range(3):
                for c in range(3):
                    if grid[r0+r][c0+c] == 4:
