def solve_6e82a1ae(grid):
    rows, cols = len(grid), len(grid[0])
    out = [[0]*cols for _ in range(rows)]
    visited = set()
    blobs = []
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 5 and (r,c) not in visited:
                blob = []
                stack = [(r,c)]
                while stack:
                    cr,cc = stack.pop()
                    if (cr,cc) in visited or grid[cr][cc] != 5:
                        continue
                    visited.add((cr,cc))
                    blob.append((cr,cc))
                    for dr,dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr,nc = cr+dr,cc+dc
                        if 0<=nr<rows and 0<=nc<cols and (nr,nc) not in visited:
                            stack.append((nr,nc))
                blobs.append(blob)
    sizes = sorted(set(len(b) for b in blobs), reverse=True)
    size_to_color = {s: i+1 for i, s in enumerate(sizes)}
    for blob in blobs:
        color = size_to_color[len(blob)]
        for r,c in blob:
            out[r][c] = color
    return out

